import{_ as t,o as r,c as i,a2 as o}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Démarrage Rapide — Annonceurs","description":"","frontmatter":{"title":"Démarrage Rapide — Annonceurs"},"headers":[],"relativePath":"docs/fr/advertisers/onboarding-quick-start.md","filePath":"docs/fr/advertisers/onboarding-quick-start.md"}'),a={name:"docs/fr/advertisers/onboarding-quick-start.md"};function s(n,e,l,d,u,c){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="demarrage-rapide-—-annonceurs" tabindex="-1">Démarrage Rapide — Annonceurs <a class="header-anchor" href="#demarrage-rapide-—-annonceurs" aria-label="Permalink to &quot;Démarrage Rapide — Annonceurs&quot;">​</a></h1><p class="gi-page-intro">Vous souhaitez lancer votre première campagne sur getinside. En 4 étapes (15 minutes), vous avez une campagne en cours de diffusion.</p><div class="gi-accent-box"><strong>Ce guide est pour vous si :</strong> vous avez un compte getinside (ou êtes en train d&#39;en créer un) et voulez lancer votre première campagne rapidement. </div><hr><h2 id="etape-1-—-creez-votre-compte-3-min" tabindex="-1">Étape 1 — Créez votre compte (3 min) <a class="header-anchor" href="#etape-1-—-creez-votre-compte-3-min" aria-label="Permalink to &quot;Étape 1 — Créez votre compte (3 min)&quot;">​</a></h2><p>L&#39;accès est <strong>réservé aux professionnels</strong> (SIRET requis).</p><ol><li>Rendez-vous sur <a href="https://app.getinside.media/" target="_blank" rel="noreferrer">app.getinside.media</a></li><li>Cliquez sur <strong>&quot;Créer un compte&quot;</strong></li><li>Renseignez vos informations : nom, email, SIRET, coordonnées de facturation</li><li>Validez votre email → votre compte est activé</li></ol><blockquote><p>Si vous avez été invité par votre gestionnaire de compte, ouvrez l&#39;email d&#39;invitation et cliquez sur le lien d&#39;activation.</p></blockquote><hr><h2 id="etape-2-—-choisissez-votre-format-2-min" tabindex="-1">Étape 2 — Choisissez votre format (2 min) <a class="header-anchor" href="#etape-2-—-choisissez-votre-format-2-min" aria-label="Permalink to &quot;Étape 2 — Choisissez votre format (2 min)&quot;">​</a></h2><p>Chaque format cible un objectif différent :</p><table tabindex="0"><thead><tr><th>Format</th><th>Objectif idéal</th><th>Délai typique</th></tr></thead><tbody><tr><td><strong>📦 Insertion Colis</strong></td><td>Acquisition physique, notoriété, trafic offline→online</td><td>2-4 semaines</td></tr><tr><td><strong>📧 Emailing Dédié</strong></td><td>Acquisition email, trafic direct</td><td>1-2 semaines</td></tr><tr><td><strong>📩 Display Email</strong></td><td>Visibilité, remarketing</td><td>1 semaine</td></tr><tr><td><strong>📱 Social Ads</strong></td><td>Engagement, visibilité réseaux sociaux</td><td>1-2 semaines</td></tr><tr><td><strong>🎁 Jeu Concours</strong></td><td>Collecte de leads qualifiés</td><td>2-3 semaines</td></tr></tbody></table><blockquote><p>Pas sûr ? Votre gestionnaire de compte getinside vous conseille selon vos objectifs lors d&#39;un appel de 15 minutes.</p></blockquote><hr><h2 id="etape-3-—-soumettez-votre-brief-5-min" tabindex="-1">Étape 3 — Soumettez votre brief (5 min) <a class="header-anchor" href="#etape-3-—-soumettez-votre-brief-5-min" aria-label="Permalink to &quot;Étape 3 — Soumettez votre brief (5 min)&quot;">​</a></h2><p><strong>Espace :</strong> Mes Campagnes → Créer une campagne</p><p>Vous aurez besoin de :</p><p><strong>Informations de base :</strong></p><ul><li>Volume souhaité (nombre de colis, contacts, impressions selon le format)</li><li>Budget et dates de diffusion</li><li>URL de destination (avec UTM si possible)</li></ul><p><strong>Matière créative :</strong></p><ul><li>La promesse de votre offre (ex: &quot;-20% pour les nouveaux clients&quot;)</li><li>Vos visuels (selon les <a href="/handbook/docs/fr/advertisers/sponsored-mail/design-guide/print-specs.html">spécifications techniques</a>)</li><li>Vos arguments clés</li></ul><blockquote><p>Pas de visuels ? Le <strong>Studio getinside</strong> crée vos supports créatifs. Contactez votre gestionnaire pour en savoir plus.</p></blockquote><hr><h2 id="etape-4-—-selectionnez-vos-distributeurs-et-validez-5-min" tabindex="-1">Étape 4 — Sélectionnez vos distributeurs et validez (5 min) <a class="header-anchor" href="#etape-4-—-selectionnez-vos-distributeurs-et-validez-5-min" aria-label="Permalink to &quot;Étape 4 — Sélectionnez vos distributeurs et validez (5 min)&quot;">​</a></h2><ol><li>La plateforme vous propose une <strong>sélection de distributeurs</strong> dont l&#39;audience correspond à vos critères</li><li>Consultez les profils : secteur, panier moyen, volume hebdomadaire</li><li>Les distributeurs reçoivent votre proposition et peuvent <strong>accepter, refuser ou contre-proposer</strong></li><li>Une fois l&#39;accord trouvé, <strong>validez la campagne en moins de 48h ouvrées</strong> → un Bon de Commande est généré automatiquement</li><li>Validez le <strong>BAT (Bon à Tirer)</strong> — dernière vérification visuelle et technique avant la mise en production</li></ol><hr><h2 id="votre-campagne-est-lancee-✅" tabindex="-1">Votre campagne est lancée ✅ <a class="header-anchor" href="#votre-campagne-est-lancee-✅" aria-label="Permalink to &quot;Votre campagne est lancée ✅&quot;">​</a></h2><p>Suivez les performances en temps réel dans <strong>Mes Campagnes → Statistiques</strong>.</p><p><strong>Rappel important :</strong> La validation dans les 48h est contractuelle — passé ce délai, la campagne peut être annulée et des frais peuvent s&#39;appliquer.</p><hr><p><strong>Prochaines étapes :</strong></p><ul><li><a href="/handbook/docs/fr/advertisers/sponsored-mail/">Guide Insertion Colis</a> — specs techniques et créa</li><li><a href="/handbook/docs/fr/advertisers/pricing.html">Pricing &amp; Offres</a> — tarifs et niveaux de service</li><li><a href="/handbook/docs/fr/resources/studio.html">Studio Créatif</a> — déléguer la création de vos supports</li></ul>',32)])])}const g=t(a,[["render",s]]);export{m as __pageData,g as default};
